/**
 * 定义一个类efuAI来处理AI相关的功能
 */
class efuAI{
    /**
     * 构造函数，初始化类的属性
     */
    constructor(){
        this.root="https://summary.tianli0.top",// API服务器地址
        this.aiTalkMode=!1,// AI对话模式开关
        this.aiPostExplanation='',// 文章的AI解释
        this.config=GLOBAL_CONFIG.post_ai,// AI配置
        this.scoGPTIsRunning=!1// AI处理状态
    }
    /**
     * 初始化AI功能
     */
    init(){
        // 检查是否存在AI解释的容器，如果不存在则不执行后续操作
        if(!document.querySelector(".ai-explanation"))return;
        // 重置AI处理状态
        this.scoGPTIsRunning=!1;
        // 根据页面配置获取AI解释文本
        this.aiPostExplanation=PAGE_CONFIG.ai_text?PAGE_CONFIG.ai_text+"":false;
        // 如果没有AI解释文本，则生成一个
        if(!this.aiPostExplanation){
            this.generate()
        }else{
            // 否则直接显示
            this.aiShowAnimation(Promise.resolve(this.aiPostExplanation))
        }
        // 初始化AI引擎
        this.AIEngine()
    }
    /**
     * 获取文章标题和内容
     * @returns {string} 文章标题和内容的组合字符串
     */
    getTitleAndContent(){
        const e=document.getElementById("article-container"),// 获取文章容器
        t=document.title,// 获取文档标题
        n=e.getElementsByTagName("p"),// 获取所有段落
        i=e.querySelectorAll("h1, h2, h3, h4, h5");// 获取所有标题
        return(t+" "+Array.from(i).concat(Array.from(n)).map((e=>e.innerText.replace(/https?:\/\/[^\s]+/g,""))).join(" ")).slice(0,1e3)// 组合并返回标题和内容
    }
    /**
     * 生成AI解释文本
     */
    async generate(){
        // 显示生成中的动画
        this.aiShowAnimation(this.fetch(document.title,this.getTitleAndContent(),this.config.key))
    }
    /**
     * 发起网络请求以获取AI解释文本
     * @param {string} e 文章标题
     * @param {string} t 文章内容
     * @param {string} n AI服务的密钥
     * @returns {Promise<string>} 包含AI解释文本的Promise对象
     */
    async fetch(e,t,n){
        const i=`${this.root}/?content=${encodeURIComponent(t)}&title=${e}&key=${encodeURIComponent(n)}&url=${encodeURIComponent(window.location.href)}`,// 构造请求URL
        s=await fetch(i),// 发起请求
        o=await s.json();// 解析响应
        return s.ok?(this.aiPostExplanation=o.summary,o.summary):(console.error("Request failed:",o.err_msg),o.err_msg)// 处理响应
    }
    /**
     * 显示AI解释的动画效果
     * @param {Promise<string>} e 包含AI解释文本的Promise对象
     * @param {boolean} t 是否是对话模式
     */
    aiShowAnimation(e,t=!1){
        const n=document.querySelector(".ai-explanation"),// 获取AI解释的容器
        i=document.querySelector(".ai-tag");// 获取AI标签
        if(!n||this.scoGPTIsRunning)return;// 检查条件
        // 准备显示生成中的动画
        this.scoGPTIsRunning=!0,this.cleanSuggestions(),i.classList.add("loadingAI"),n.style.display="block",n.innerHTML='生成中...<span class="blinking-cursor"></span>';
        let s,o,a=!0,c=0,r=!0;// 声明变量
        const l=new IntersectionObserver((e=>{a=e[0].isIntersecting,a&&requestAnimationFrame(o)}),{threshold:0});// 创建观察者
        // 处理AI解释文本的显示
        e.then((e=>{s=performance.now(),o=()=>{if(c<e.length&&a){const r=performance.now(),g=r-s,h=e.slice(c,c+1),u=/[，。！、？,.!?]/.test(h),m=/[a-zA-Z0-9]/.test(h);g>=(u?100*Math.random()+100:m?10:25)&&(n.innerText=e.slice(0,c+1),s=r,c++,c<e.length?n.innerHTML=e.slice(0,c)+'<span class="blinking-cursor"></span>':(n.innerHTML=e,n.style.display="block",this.scoGPTIsRunning=!1,i.classList.remove("loadingAI"),l.disconnect(),t&&this.createSuggestions())),a&&requestAnimationFrame(o)}},a&&r&&setTimeout((()=>{requestAnimationFrame(o),r=!1}),3e3),l.observe(n)})).catch((e=>{console.error("检索信息失败：",e),n.innerHTML="检索信息失败",n.style.display="block",this.scoGPTIsRunning=!1,i.classList.remove("loadingAI"),l.disconnect()}))// 处理错误
    }
    /**
     * 初始化AI引擎
     */
    AIEngine(){
        const e=document.querySelector(".ai-tag");// 获取AI标签
        e&&e.addEventListener("点击",(()=>{this.scoGPTIsRunning||(this.aiTalkMode=!0,this.aiShowAnimation(Promise.resolve(this.config.talk),!0))}))// 绑定点击事件处理函数
    }
    /**
     * 清理建议
     */
    cleanSuggestions(){
        const e=document.querySelector(".ai-suggestions");// 获取建议容器
        e?e.innerHTML="":console.error("没有这个元素：'ai-suggestions'")// 清空建议或输出错误
    }
    /**
     * 创建建议
     */
    createSuggestions(){
        if(this.aiTalkMode){
            this.cleanSuggestions(),// 清空原有建议
            this.createSuggestionItemWithAction("这篇文章讲了什么？",(()=>{""===this.aiPostExplanation?this.generate():this.aiShowAnimation(Promise.resolve(this.aiPostExplanation),!0)})),// 创建建议项
            this.config.randomPost&&this.createSuggestionItemWithAction("带我去看看其他文章",(()=>toRandomPost())),// 如果配置允许，创建随机文章建议项
            this.aiTalkMode=!0// 保持对话模式状态
        }
    }
    /**
     * 创建带有操作的建议项
     * @param {string} e 建议项文本
     * @param {Function} t 点击建议项时执行的函数
     */
    createSuggestionItemWithAction(e,t){
        const n=document.querySelector(".ai-suggestions");// 获取建议容器
        if(!n)return void console.error("无法找到具有class为ai-suggestions的元素")// 如果没有建议容器则输出错误
        const i=document.createElement("div");// 创建建议项元素
        i.classList.add("ai-suggestions-item"),i.textContent=e,i.addEventListener("click",t),n.appendChild(i)// 设置建议项属性并添加到容器中
    }
}
const efu_ai=new efuAI;// 创建efuAI实例